`Java` solution using UnionFind based on https://leetcode.com/problems/accounts-merge/
Time complexity: `O(n * α(n))`, where `α(n)` is the [inverse Ackermann function](https://en.wikipedia.org/wiki/Disjoint-set_data_structure#Time_complexity).
Space complexity: `O(n)`.
```
public List<List<Integer>> merge(int[][] input) {
    int n = input.length;
    UF uf = new UF(n);
    Map<Integer, Integer> valToId = new HashMap<>();

    for (int i = 0; i < n; i++) {
        int[] tuple = input[i];
        valToId.putIfAbsent(tuple[0], i);
        valToId.putIfAbsent(tuple[1], i);
        uf.union(valToId.get(tuple[0]), valToId.get(tuple[1]));
    }

    Map<Integer, List<Integer>> idToVal = new HashMap<>();

    for (Map.Entry<Integer, Integer> entry : valToId.entrySet()) {
        int id = uf.find(entry.getValue());
        idToVal.putIfAbsent(id, new ArrayList<>());
        idToVal.get(id).add(entry.getKey());
    }

    return new ArrayList<>(idToVal.values());
}

class UF {
    private int[] parent;  // parent[i] = parent of i
    private byte[] rank;   // rank[i] = rank of subtree rooted at i (never more than 31)

    public UF(int n) {
        if (n < 0) throw new IllegalArgumentException();
        parent = new int[n];
        rank = new byte[n];
        for (int i = 0; i < n; i++) {
            parent[i] = i;
        }
    }

    public int find(int p) {
        while (p != parent[p]) {
            parent[p] = parent[parent[p]];
            p = parent[p];
        }
        return p;
    }

    public void union(int p, int q) {
        int pr = find(p);
        int qr = find(q);
        if (pr == qr) return;
        if (rank[pr] < rank[qr]) {
            parent[pr] = qr;
        } else {
            parent[qr] = pr;
            if (rank[pr] == rank[qr]) rank[pr]++;
        }
    }
}
