import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class TupleMerger {
    // Union-Find class
    static class UF {
        private int[] parent;
        private byte[] rank;

        public UF(int n) {
            parent = new int[n];
            rank = new byte[n];
            for (int i = 0; i < n; i++) {
                parent[i] = i;
            }
        }

        public int find(int p) {
            while (p != parent[p]) {
                parent[p] = parent[parent[p]]; // Path compression
                p = parent[p];
            }
            return p;
        }

        public void union(int p, int q) {
            int rootP = find(p);
            int rootQ = find(q);
            if (rootP == rootQ) return;

            // Make smaller rank root point to larger one
            if (rank[rootP] < rank[rootQ]) {
                parent[rootP] = rootQ;
            } else {
                parent[rootQ] = rootP;
                if (rank[rootP] == rank[rootQ]) {
                    rank[rootP]++;
                }
            }
        }
    }

    // Function to merge tuples
    public static List<List<Integer>> merge(int[][] input) {
        int n = input.length;
        UF uf = new UF(n);
        Map<Integer, Integer> valToId = new HashMap<>();

        for (int i = 0; i < n; i++) {
            int[] tuple = input[i];
            if (!valToId.containsKey(tuple[0])) {
                valToId.put(tuple[0], i);
            }
            if (!valToId.containsKey(tuple[1])) {
                valToId.put(tuple[1], i);
            }
            uf.union(valToId.get(tuple[0]), valToId.get(tuple[1]));
        }

        Map<Integer, List<Integer>> idToVal = new HashMap<>();
        for (Map.Entry<Integer, Integer> entry : valToId.entrySet()) {
            int id = uf.find(entry.getValue());
            if (!idToVal.containsKey(id)) {
                idToVal.put(id, new ArrayList<Integer>());
            }
            idToVal.get(id).add(entry.getKey());
        }

        return new ArrayList<>(idToVal.values());
    }

    // Main method for testing
    public static void main(String[] args) {
        int[][] input = {{1, 2}, {3, 4}, {7, 2}, {5, 12}, {11, 3}, {9, 7}};
        List<List<Integer>> result = merge(input);
        System.out.println(result);
    }
}
